import numpy as np

class Board:
    def __init__(self):
        self.board = np.zeros((BOARD_SIZE, BOARD_SIZE), dtype=int)
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces in their starting positions
        for i in range(3):
            for j in range(i % 2, BOARD_SIZE, 2):
                self.board[i][j] = Piece.BLACK.value
        for i in range(5, 8):
            for j in range(i % 2, BOARD_SIZE, 2):
                self.board[i][j] = Piece.WHITE.value

    def print_board(self):
        # Print the board in a readable format
        for row in self.board:
            print(" ".join(f"{piece.name if piece != Piece.EMPTY else ' '}" for piece in row))

    def get_piece(self, row, col):
        return Piece(self.board[row][col])

    def set_piece(self, row, col, piece):
        self.board[row][col] = piece.value

    def is_valid_move(self, row, col, direction, capture=False):
        # Check if a move or capture is valid
        target_row = row + direction.value[0]
        target_col = col + direction.value[1]

        if not (0 <= target_row < BOARD_SIZE and 0 <= target_col < BOARD_SIZE):
            return False

        target_piece = self.get_piece(target_row, target_col)

        if capture:
            # Check for a valid capture
            jump_row = row + direction.value[0] * 2
            jump_col = col + direction.value[1] * 2
            if (not (0 <= jump_row < BOARD_SIZE and 0 <= jump_col < BOARD_SIZE)):
                return False
            jump_piece = self.get_piece(jump_row, jump_col)
            if jump_piece != Piece.EMPTY:
                return False
            if target_piece == piece or target_piece == Piece.EMPTY:
                return False

        return True

    def make_move(self, start_row, start_col, end_row, end_col):
        # Make a move on the board
        piece = self.get_piece(start_row, start_col)
        capture = abs(end_row - start_row) == 2
        if self.is_valid_move(start_row, start_col, Direction((end_row - start_row) // abs(end_row - start_row), (end_col - start_col) // abs(end_col - start_col)), capture):
            self.set_piece(end_row, end_col, piece)
            self.set_piece(start_row, start_col, Piece.EMPTY.value)

    def check_winner(self):
        # Check if there is a winner
        black_count = np.sum(self.board == Piece.BLACK.value)
        white_count = np.sum(self.board == Piece.WHITE.value)

        if black_count == 0:
            return "White wins"
        elif white_count == 0:
            return "Black wins"
        else:
            return None

    def get_all_moves(self, player):
        # Get all possible moves for a given player
        moves = []
        for i in range(BOARD_SIZE):
            for j in range(BOARD_SIZE):
                piece = self.get_piece(i, j)
                if (player == Piece.BLACK and piece in [Piece.BLACK, Piece.BLACK_KING]) or (player == Piece.WHITE and piece in [Piece.WHITE, Piece.WHITE_KING]):
                    for direction in Direction:
                        move = ((i, j), (i + direction.value[0], j + direction.value[1]))
                        if self.is_valid_move(*move):
                            moves.append(move)
        return moves
